const express = require('express');
const crypto = require('crypto');
const app = express();

// In-memory storage for authorization codes and tokens
const authCodes = new Map();
const accessTokens = new Map();
const clients = new Map(); // client_id -> { client_secret, redirect_uris }

// Add a client (in production, this would be stored securely)
clients.set('myclient', {
  client_secret: 'myclientsecret',
  redirect_uris: ['http://localhost:3000/callback']
});

// Middleware to parse JSON
app.use(express.json());

// Generate secure random string
function generateRandomString(length) {
  return crypto.randomBytes(length).toString('hex');
}

// Validate redirect_uri against client's allowed URIs
function validateRedirectUri(clientId, redirectUri) {
  const client = clients.get(clientId);
  if (!client) return false;
  return client.redirect_uris.includes(redirectUri);
}

// Validate client credentials
function validateClientCredentials(clientId, clientSecret) {
  const client = clients.get(clientId);
  if (!client) return false;
  return client.client_secret === clientSecret;
}

// Authorization endpoint
app.get('/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state } = req.query;

  // Validate required parameters
  if (!response_type || response_type !== 'code') {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Invalid response type' });
  }

  if (!client_id) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing client_id' });
  }

  if (!redirect_uri) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing redirect_uri' });
  }

  // Validate client credentials
  if (!validateClientCredentials(client_id, req.headers.authorization?.split(' ')[1])) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
  }

  // Validate redirect_uri
  if (!validateRedirectUri(client_id, redirect_uri)) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Invalid redirect_uri' });
  }

  // Simulate user consent (in production, this would be a real UI)
  const consent = true; // Assume user consents

  if (consent) {
    // Generate authorization code
    const code = generateRandomString(32);
    const codeExpiry = Date.now() + 600000; // 10 minutes

    // Store authorization code with user consent
    authCodes.set(code, {
      client_id,
      redirect_uri,
      scope,
      state,
      expires_at: codeExpiry,
      user_id: 'user123' // In production, this would be the actual authenticated user
    });

    // Redirect with authorization code
    const redirectUrl = new URL(redirect_uri);
    redirectUrl.searchParams.append('code', code);
    if (state) redirectUrl.searchParams.append('state', state);
    
    return res.redirect(redirectUrl.toString());
  } else {
    return res.status(400).json({ error: 'access_denied', error_description: 'User denied consent' });
  }
});

// Token endpoint
app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  // Validate grant type
  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type', error_description: 'Invalid grant type' });
  }

  // Validate required parameters
  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing authorization code' });
  }

  if (!client_id) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing client_id' });
  }

  if (!client_secret) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing client_secret' });
  }

  // Validate client credentials
  if (!validateClientCredentials(client_id, client_secret)) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
  }

  // Validate authorization code
  const authCode = authCodes.get(code);
  if (!authCode) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid authorization code' });
  }

  // Check if code has expired
  if (authCode.expires_at < Date.now()) {
    authCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code has expired' });
  }

  // Check if redirect_uri matches
  if (authCode.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Mismatched redirect_uri' });
  }

  // Generate access token
  const accessToken = generateRandomString(40);
  const refreshToken = generateRandomString(40);
  const tokenExpiry = Date.now() + 3600000; // 1 hour

  // Store access token
  accessTokens.set(accessToken, {
    client_id,
    user_id: authCode.user_id,
    scope: authCode.scope,
    expires_at: tokenExpiry
  });

  // Remove used authorization code
  authCodes.delete(code);

  // Return token response
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: refreshToken,
    scope: authCode.scope
  });
});

